import{_ as o,c as r,o as a,ae as p}from"./chunks/framework.BvcDoAct.js";const d=JSON.parse('{"title":"Novel Core","description":"","frontmatter":{},"headers":[],"relativePath":"zh-cn/Management2Extra/02_Interview/01_NovelCore/01_NovelCore.md","filePath":"zh-cn/Management2Extra/02_Interview/01_NovelCore/01_NovelCore.md"}'),t={name:"zh-cn/Management2Extra/02_Interview/01_NovelCore/01_NovelCore.md"};function n(l,e,i,s,_,c){return a(),r("div",null,[...e[0]||(e[0]=[p('<p>Interview - Novel Core</p><h1 id="novel-core" tabindex="-1">Novel Core <a class="header-anchor" href="#novel-core" aria-label="Permalink to &quot;Novel Core&quot;">​</a></h1><h3 id="轮到我成为-英雄-的时候了" tabindex="-1">轮到我成为“英雄”的时候了 <a class="header-anchor" href="#轮到我成为-英雄-的时候了" aria-label="Permalink to &quot;轮到我成为“英雄”的时候了&quot;">​</a></h3><blockquote><p>在23岁生日当天，Novel Core 发表了第3张专辑《HERO》。 他不仅为电视动画《キングダム》演唱片尾曲等，展现出亮眼的活跃表现，如今也已经朝着下一个梦想迈进。</p></blockquote><p>[2024年3月号再录]<br> 文：小松香里<br> 照片：兴梠真穂<br> 发型化妆：クジメグミ(L&amp;Co。)</p><p>2024年1月18日，在首次日本武道馆公演的第二天、23岁生日当天，Novel Core 惊喜发行了主流出道后的第3张专辑《HERO》。</p><p>Core 开始憧憬武道馆公演，是受到2017年 SKY-HI 武道馆演唱会的影响。SKY-HI 一边受到地下嘻哈的影响，一边在主流领域开辟出一条无人走过的道路。对当时的 Core 来说，用一句话形容，他就是“英雄”。将这个特别的词作为专辑名称，正体现了他巨大的觉悟。</p><p>对一名艺术家来说，在日本武道馆举办演出，意味着再也无法用年龄或资历作为借口。因此我觉得，在这个时间点，自己必须像2017年时日高(光啓/SKY-HI)先生之于我那样，成为能够明确给予下一代希望的人，也就是具备作为“被追赶的一方”的意识。正因为如此，我将这张专辑命名为《HERO》，用来划分“过去”和“未来”。</p><p><strong>专辑以总结自己从15岁踏入说唱世界到登上武道馆舞台这段历程的说唱曲《I AM THE》开篇，并以由2023年组建的常设乐队「THE WILL RABBITS」制作的乐队曲《HERO》收尾。这一结构本身也具有重要意义。</strong></p><p>这两年里，我持续创作了既遵循嘻哈范式，又跨越流派边界、融合摇滚和流行等多种元素的音乐。在这个过程中，“这才是我真正想做的东西”自然而然地汇聚成了专辑中的曲目。</p><p>我有一种自负：说唱既是我的出身，也是我最大的武器。所以这张作品必须从这样的歌曲开始。《I AM THE》最初只是一个更短的 demo，结果变成了一首持续超过40小节全程说唱的作品。我想写的不是那种“赚了钱”或“在大场馆演出”这种任何成功者都能唱的内容，而是只能从我亲眼见过的景色中才能说出的歌词——结果呈现出一种“自我夸耀（boasting）”结构的表达。因此我把 Zeebra、般若等对我有恩的人写进歌词里，使之成为一首极其私人的作品。</p><p>最后的《HERO》是与常设乐队成员一起完成的歌曲。最初我是沉迷于摇滚而接触音乐，后来经历嘻哈，一直以独行者的姿态活动，因此对“乐队”始终抱有憧憬。从一个人孤独而克己地进行说唱的开端，到以《HERO》唱出象征这三年的歌词作为收尾，这样的流动对我来说，正是一种同时让人感受到“至今为止”和“从今以后”的故事。</p><h3 id="能够展现-脆弱-的时代" tabindex="-1">能够展现“脆弱”的时代 <a class="header-anchor" href="#能够展现-脆弱-的时代" aria-label="Permalink to &quot;能够展现“脆弱”的时代&quot;">​</a></h3><p><strong>《HERO》中描绘的英雄形象，并非完美无缺，而是一个深受伤害、理解痛苦、并向同伴伸出援手的真实英雄。</strong></p><p>在2017年时的我看来，以日高先生为首，那些走在前方、给予我希望的艺术家们，都是闪闪发光、无敌的英雄。但在追逐他们背影的过程中我才意识到，正因为他们也经历过无数伤痛，正因为他们脆弱易碎，所以他们才是英雄。</p><p>正因如此，他们才会向当时虚弱的我伸出手来。把这份领悟在这个时间点写进歌曲，我觉得也等同于拯救了过去的自己。日高先生常说的“温柔的复仇”，直到现在我走上同样道路，才终于真正理解。</p><p>我深刻地觉得，文化是一个循环。我也希望自己能够承接这种循环。如果听过我音乐的人，在几年后也能像现在的我一样去思考，并试着把某些东西传递给下一代，那将是一件非常美好的事。《HERO》正是面向这样的未来而创作的一首歌。</p><p>说得简单一点，如果有人陷入困境，我就想去帮助他。我觉得没有必要去考虑对方处在什么位置，或是自己会被如何看待。大家都是在争分夺秒地活着。至少2017年的我是这样。我想成为像日高先生那样，能够毫不犹豫伸出援手的人，并以这样的信念作为自己的核心继续活动。</p><p>有同伴总是更好。真正的孤身一人，与哪怕只有一个愿意理解你的人之间，是完全不同的。我一直在想，自己要成为别人生命中的“那一个人”，并以此为念去创作音乐。</p><p>从我15岁开始做音乐到现在，我感觉随着时代的变化，艺术家的“魅力”也发生了巨大转变。过去，艺术家往往带有某种强烈的“男子气概”，把张扬、耍帅视为成为明星的标志。尤其是在嘻哈圈，这种风潮更为明显，甚至形成了“不装酷就无法生存”的氛围。我自己也曾强烈地认为，在人前展现脆弱或流泪是一件不够帅气的事。</p><p>但随着以 Lil Peep 为代表、受到摇滚影响的嘻哈艺术家出现，他们开始认真地把心理健康问题以及自身的脆弱作为主题来歌唱。于是，艺术家的魅力不再只是“装酷”，而是可以以真实的姿态，把艰难的一面也展现给粉丝。我也因为这些艺术家的出现，而变得更容易活下去。</p><p>我之所以能够对粉丝更加敞开心扉，很大程度上也是因为这种时代潮流以及自身心境的变化。简单来说，我越来越能够在“作为一个人本身也处于幸福状态”的前提下去做音乐。这种变化，我觉得也被描绘在《HERO》中。</p><h3 id="将选择变成正确" tabindex="-1">将选择变成正确 <a class="header-anchor" href="#将选择变成正确" aria-label="Permalink to &quot;将选择变成正确&quot;">​</a></h3><p><strong>武道馆演出的曲目编排以《HERO》为轴心展开。同时，通过事先进行的众筹，以超过目标金额810%（约4060万日元）的惊人达成率筹集到资金，使 Core 从8年前立志走上音乐道路时埋下的伏线得以回收。</strong></p><p>我之所以进行众筹，其中一个很大的理由，是想加入合唱团作为不可或缺的演出元素，让这场演出成为一场能够像当年我从日高先生那里得到的那样，把某些东西托付给下一代的舞台。</p><p>在中学时，我因为在合唱比赛中担任指挥，感受到了音乐巨大的力量，并决定走上音乐道路。但由于资金和学力的问题，我放弃了报考音乐大学，也正是在那个时候接触到了嘻哈，觉得“说唱或许可以”，于是立志成为一名说唱歌手。正因如此，我一直想实现这样一种形式：用自己创作的歌曲，由自己担任指挥，让大家一起歌唱。我希望看到这个舞台的孩子们，像当年的我一样，虽然烦恼、对未来怀有模糊的不安，但哪怕是间接地，也能在今后的人生中获得继续前行的动力。</p><p>大约在3年前、临近主流出道之前，我很少有机会让别人理解我想做的事情。再加上自身的脆弱，我不愿向周围敞开心扉，也不去建立伙伴关系，带着这样的心态在活动。</p><p>但在加入BMSG之后，值得信赖的工作人员逐渐增加，与 OUTER（Novel Core 粉丝的称呼）之间的沟通也变得更加紧密，我终于能够以自己理想的方式开展活动。也正因如此，在主流出道之后，我会在每一部作品中划分自己的阶段，并重新定义自己的定位。</p><p>从第1张专辑《A GREAT FOOL》中那个无所畏惧的“大傻瓜”——“愚者”出发，卷入他人形成漩涡，成为“麻烦”（单曲《TROUBLE》），再抵达象征这个时代的“图标”（EP《iCon》），最终成为将希望传递给下一代的“英雄”。这三年来，我一直重视着这样一条叙事线。</p><p>包括刚开始做独立音乐的时期在内，我也经历过痛苦到想要放弃的阶段。但为了能够快乐地继续做音乐，我曾选择暂停活动，也曾背负1000万日元的债务制作专辑。与其说每一次都“没有选错”，不如说是通过之后的活法，把那些选择变成了“正确”。</p><p>今后我也一定会面临各种需要做出选择的瞬间，但正如《HERO》的歌词中所写：“我想选择那个无论结果如何都能笑着面对的‘自己’”。无论做出哪种选择，我都希望活成一个不会后悔的人生。</p><p><strong>在武道馆公演与专辑《HERO》的发行这一重要节点之后，他将迈入怎样的新阶段？</strong></p><p>虽然活动内容本身不会发生大的改变，但在我自己的感受上，会明确转变为“从这里开始才是真正的胜负”。至今为止，很多人是在理解了我的背景之后来享受我的音乐，因此在某种意义上，我并不需要成为所谓的“热门艺人”。但从现在开始，是一个必须真正用音乐一决高下的阶段。必须让更多的人听到我的音乐。</p><p>就我个人而言，我把2024年和2025年作为一个整体阶段来思考，并在进行各种规划。2024年既是执行的一年，也是播种的一年，我会同时推进这两件事。</p>',34)])])}const E=o(t,[["render",n]]);export{d as __pageData,E as default};
